import Axios, { CancelToken, Cancel } from "axios";

const SERVER_URL =
  process.env.NODE_ENV === "production"
    ? "https://ollehmichael.github.io"
    : "https://ollehmichael.github.io";
// : "http://localhost:3001";

export function Login(
  username: string,
  password: string,
  cancelToken?: CancelToken
) {
  return wrapper.POST_NO_AUTH(
    "/auth/signin",
    {
      username: username,
      password: password,
    },
    cancelToken
  );
}

